firstAgent.answer:
agent 함수를 임포트하고 provider, instructions, 그리고 선택적 성격 특성으로 구성하세요. 최소한의 예:

import { agent } from '@framers/agentos'

const myAgent = agent({
  provider: 'openai',
  instructions: '당신은 도움이 되는 어시스턴트입니다.',
  personality: { openness: 0.8, conscientiousness: 0.9 },
  memory: { enabled: true },
})

const reply = await myAgent.send('안녕하세요!')
console.log(reply.text)
